sql_query:
SELECT "Year"
FROM clinical_trials
WHERE "Name of ICI" = 'Nivolumab';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Year" AS source_value FROM clinical_trials
WHERE "Name of ICI" = 'Nivolumab'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_era_bucket(source_value) AS "era"
FROM base;
